هر صفحه ۱۵ اشتراک نمایش داده می‌شود.",$kb);exit;}if(preg_match('/^expiredSubView(\d+)_(pg|other)_([01])_(\d+)$/',$data,$m)){$id=(int)$m[1];$st=$connection->prepare("SELECT o.*,s.type server_type,COALESCE(si.title,s.type) server_title FROM orders_list o JOIN server_config s ON s.id=o.server_id LEFT JOIN server_info si ON si.id=o.server_id WHERE o.id=? LIMIT 1");$st->bind_param('i',$id);$st->execute();$o=$st->get_result()->fetch_assoc();$st->close();if(!$o){alert('پیدا نشد',true);exit;}$x=adminExpiredDbState($o);$at=$x['ended_at']?date('Y-m-d H:i',$x['ended_at']):'نامشخص';$kb=json_encode(['inline_keyboard'=>[[['text'=>'🗑 حذف این اشتراک','callback_data'=>'expiredSubDelete'.$id.'_'.$m[2].'_'.$m[3].'_'.$m[4]]],[['text'=>'🔙 بازگشت','callback_data'=>'expiredSubsList_'.$m[2].'_'.$m[3].'_'.$m[4]]]]],JSON_UNESCAPED_UNICODE);smartSendOrEdit($message_id,"🗑 اشتراک تمام‌شده

🆔 {$id}
👤 {$o['userid']}
🔮 {$o['remark']}
🖥 {$o['server_title']}
⚠️ {$x['reason']}
🕒 {$at}",$kb);exit;}if(preg_match('/^expiredSubDelete(\d+)_(pg|other)_([01])_(\d+)$/',$data,$m)){[$ok,$msg]=adminDeleteExpiredOrder((int)$m[1]);if(!$ok){alert($msg,true);exit;}[$kb,$c]=adminExpiredKeyboard($m[2],(int)$m[3]===1,(int)$m[4]);smartSendOrEdit($message_id,"✅ حذف شد
باقی‌مانده: {$c}",$kb);exit;}if(preg_match('/^expiredSubsBulkAsk_(pg|other)_([01])$/',$data,$m)){$c=adminExpiredCount($m[1],(int)$m[2]===1);$kb=json_encode(['inline_keyboard'=>[[['text'=>'✅ حذف همه ('.$c.')','callback_data'=>'expiredSubsBulkDo_'.$m[1].'_'.$m[2]]],[['text'=>'❌ انصراف','callback_data'=>'expiredSubsList_'.$m[1].'_'.$m[2].'_0']]]],JSON_UNESCAPED_UNICODE);smartSendOrEdit($message_id,"⚠️ {$c} اشتراک حذف شوند؟",$kb);exit;}if(preg_match('/^expiredSubsBulkDo_(pg|other)_([01])$/',$data,$m)){$k=$m[1];$o=(int)$m[2]===1;$ok=0;$fail=0;foreach(adminExpiredFetch($k,$o,25,0)as$x){[$d,$z]=adminDeleteExpiredOrder((int)$x['id']);$d?$ok++:$fail++;}$left=adminExpiredCount($k,$o);$kb=json_encode(['inline_keyboard'=>[$left>0?[['text'=>'ادامه حذف ('.$left.')','callback_data'=>'expiredSubsBulkDo_'.$k.'_'.($o?1:0)]]:[['text'=>'✅ پایان','callback_data'=>'expiredSubsKind_'.$k]],[['text'=>'🔙 بازگشت','callback_data'=>'expiredSubsList_'.$k.'_'.($o?1:0).'_0']]]],JSON_UNESCAPED_UNICODE);smartSendOrEdit($message_id,"✅ حذف: {$ok}
❌ ناموفق: {$fail}
📌 باقی: {$left}",$kb);exit;}}catch(Throwable$e){error_log('expired admin: '.$e->getMessage());alert('خطا ثبت شد',true);exit;}return false;}
